smooth = true

[fruit]
apple.color = "red"
apple.taste.sweet = true
"#
    .parse::<crate::RustDocument>()
    .unwrap();
    assert_eq!(
        table["fruit"]["apple"]["texture"]["smooth"].as_bool(),
        Some(true)
    );
    assert_eq!(
        table["fruit"]["apple"]["color"].as_str(),
        Some("red")
    );
    assert_eq!(
        table["fruit"]["apple"]["taste"]["sweet"].as_bool(),
        Some(true)
    );
}

